# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
import collections
import time
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Game State
# A dictionary to store all connected players
PLAYERS = {}
# A dictionary to store all items in the game world
ITEMS = {}
# A lock for the entire inventory system to prevent race conditions during item transfers
INVENTORY_LOCK = asyncio.Lock()

class Item:
    def __init__(self, item_id, name, owner_id=None):
        self.item_id = item_id
        self.name = name
        self.owner_id = owner_id # None for world item, player_id for owned item
        self.created_at = time.time()

    def to_dict(self):
        return {
            "item_id": self.item_id,
            "name": self.name,
            "owner_id": self.owner_id
        }

class Player:
    def __init__(self, player_id, websocket):
        self.player_id = player_id
        self.websocket = websocket
        self.inventory = {} # item_id -> Item object
        self.last_activity = time.time()

    async def send_message(self, message_type, data):
        try:
            message = {"type": message_type, "data": data}
            await self.websocket.send(json.dumps(message))
            self.last_activity = time.time()
        except websockets.exceptions.ConnectionClosed:
            logging.warning(f"Failed to send message to {self.player_id}: Connection closed.")

    def to_dict(self):
        return {
            "player_id": self.player_id,
            "inventory_item_ids": list(self.inventory.keys())
        }

async def initialize_world_items():
    """Create some initial items in the game world."""
    for i in range(5):
        item_id = str(uuid.uuid4())
        item = Item(item_id, f"Sword_{i+1}")
        ITEMS[item_id] = item
        logging.info(f"Initialized world item: {item.name} ({item.item_id})")

    for i in range(5):
        item_id = str(uuid.uuid4())
        item = Item(item_id, f"Potion_{i+1}")
        ITEMS[item_id] = item
        logging.info(f"Initialized world item: {item.name} ({item.item_id})")

async def get_player_inventory(player_id):
    """Returns a list of item dictionaries for a given player's inventory."""
    if player_id not in PLAYERS:
        return []
    player = PLAYERS[player_id]
    return [item.to_dict() for item in player.inventory.values()]

async def handle_request_inventory(player_id):
    """Handles a request to send the player's current inventory."""
    inventory_data = await get_player_inventory(player_id)
    player = PLAYERS[player_id]
    await player.send_message("inventory_update", {"inventory": inventory_data})
    logging.info(f"Sent inventory to {player_id}.")

async def handle_request_world_items(player_id):
    """Handles a request to send items currently without an owner (world items)."""
    world_items_data = [item.to_dict() for item in ITEMS.values() if item.owner_id is None]
    player = PLAYERS[player_id]
    await player.send_message("world_items_update", {"world_items": world_items_data})
    logging.info(f"Sent world items to {player_id}.")

async def handle_request_player_list(player_id):
    """Handles a request to send a list of all other online players."""
    online_players = [
        {"player_id": p_id, "last_activity": p.last_activity}
        for p_id, p in PLAYERS.items() if p_id != player_id
    ]
    player = PLAYERS[player_id]
    await player.send_message("player_list", {"players": online_players})
    logging.info(f"Sent player list to {player_id}.")

async def handle_request_take_item_from_world(player_id, item_id):
    """
    Handles a player taking an item from the world.
    This operation needs to be atomic and protected by a lock.
    """
    player = PLAYERS.get(player_id)
    if not player:
        logging.error(f"Player {player_id} not found for take_item_from_world.")
        return

    async with INVENTORY_LOCK:
        item = ITEMS.get(item_id)
        if not item:
            await player.send_message("error", {"message": f"Item {item_id} not found."})
            logging.warning(f"Player {player_id} tried to take non-existent item {item_id}.")
            return

        if item.owner_id is not None:
            await player.send_message("error", {"message": f"Item {item.name} is already owned by {item.owner_id}."})
            logging.warning(f"Player {player_id} tried to take owned item {item.name} ({item_id}).")
            return

        # Assign item to player
        item.owner_id = player_id
        player.inventory[item_id] = item
        await player.send_message("item_taken_success", {"item": item.to_dict()})
        logging.info(f"Player {player_id} took item {item.name} ({item_id}) from world.")

        # Notify all players about the updated world items and the player's inventory
        await broadcast_world_items_update()
        await handle_request_inventory(player_id) # Update the player's own inventory

async def handle_request_trade_item(sender_id, recipient_id, item_id):
    """
    Handles a player trading an item to another player.
    This operation needs to be atomic and protected by a lock.
    """
    sender = PLAYERS.get(sender_id)
    recipient = PLAYERS.get(recipient_id)

    if not sender:
        logging.error(f"Sender {sender_id} not found for trade_item.")
        return
    if not recipient:
        await sender.send_message("error", {"message": f"Recipient {recipient_id} not found or offline."})
        logging.warning(f"Sender {sender_id} tried to trade to non-existent recipient {recipient_id}.")
        return
    if sender_id == recipient_id:
        await sender.send_message("error", {"message": "Cannot trade with yourself."})
        logging.warning(f"Player {sender_id} tried to trade with self.")
        return

    async with INVENTORY_LOCK:
        item = sender.inventory.get(item_id)
        if not item:
            await sender.send_message("error", {"message": f"You don't own item {item_id}."})
            logging.warning(f"Player {sender_id} tried to trade item {item_id} they don't own.")
            return

        # Ensure the item's owner_id is indeed the sender_id (sanity check)
        if item.owner_id != sender_id:
            logging.critical(f"Item {item_id} has owner_id {item.owner_id} but is in {sender_id}'s inventory. Fixing.")
            item.owner_id = sender_id # Correct the discrepancy

        # Perform the transfer
        del sender.inventory[item_id]
        recipient.inventory[item_id] = item
        item.owner_id = recipient_id

        await sender.send_message("trade_success", {"message": f"You successfully traded {item.name} to {recipient_id}.", "item": item.to_dict()})
        await recipient.send_message("trade_received", {"message": f"You received {item.name} from {sender_id}.", "item": item.to_dict()})
        logging.info(f"Player {sender_id} traded item {item.name} ({item_id}) to {recipient_id}.")

        # Update inventories for both sender and recipient
        await handle_request_inventory(sender_id)
        await handle_request_inventory(recipient_id)

async def handle_request_drop_item_to_world(player_id, item_id):
    """
    Handles a player dropping an item into the world.
    This operation needs to be atomic and protected by a lock.
    """
    player = PLAYERS.get(player_id)
    if not player:
        logging.error(f"Player {player_id} not found for drop_item_to_world.")
        return

    async with INVENTORY_LOCK:
        item = player.inventory.get(item_id)
        if not item:
            await player.send_message("error", {"message": f"You don't own item {item_id}."})
            logging.warning(f"Player {player_id} tried to drop item {item_id} they don't own.")
            return

        # Ensure the item's owner_id is indeed the player_id (sanity check)
        if item.owner_id != player_id:
            logging.critical(f"Item {item_id} has owner_id {item.owner_id} but is in {player_id}'s inventory. Fixing.")
            item.owner_id = player_id # Correct the discrepancy

        # Remove item from player's inventory and make it a world item
        del player.inventory[item_id]
        item.owner_id = None # Set owner to None to signify it's a world item

        await player.send_message("item_dropped_success", {"message": f"You dropped {item.name} into the world.", "item": item.to_dict()})
        logging.info(f"Player {player_id} dropped item {item.name} ({item_id}) to world.")

        # Notify all players about the updated world items and the player's inventory
        await broadcast_world_items_update()
        await handle_request_inventory(player_id) # Update the player's own inventory

async def broadcast_world_items_update():
    """Sends the current list of world items to all connected players."""
    world_items_data = [item.to_dict() for item in ITEMS.values() if item.owner_id is None]
    message_data = {"type": "world_items_update", "data": {"world_items": world_items_data}}
    message_json = json.dumps(message_data)
    for player in PLAYERS.values():
        try:
            await player.websocket.send(message_json)
        except websockets.exceptions.ConnectionClosed:
            logging.warning(f"Failed to broadcast world items to {player.player_id}: Connection closed.")

async def handler(websocket, path):
    """
    Handles a new websocket connection. Registers the player and processes incoming messages.
    """
    player_id = str(uuid.uuid4())
    player = Player(player_id, websocket)
    PLAYERS[player_id] = player
    logging.info(f"Player {player_id} connected.")

    try:
        # Send initial connection success message and player ID
        await player.send_message("connected", {"player_id": player_id})
        await handle_request_inventory(player_id)
        await handle_request_world_items(player_id)
        await handle_request_player_list(player_id)

        async for message in websocket:
            player.last_activity = time.time()
            try:
                data = json.loads(message)
                message_type = data.get("type")
                message_data = data.get("data", {})

                logging.debug(f"Received message from {player_id}: Type={message_type}, Data={message_data}")

                if message_type == "request_inventory":
                    await handle_request_inventory(player_id)
                elif message_type == "request_world_items":
                    await handle_request_world_items(player_id)
                elif message_type == "request_player_list":
                    await handle_request_player_list(player_id)
                elif message_type == "take_item_from_world":
                    item_id = message_data.get("item_id")
                    if item_id:
                        await handle_request_take_item_from_world(player_id, item_id)
                    else:
                        await player.send_message("error", {"message": "Missing item_id for take_item_from_world."})
                elif message_type == "trade_item":
                    recipient_id = message_data.get("recipient_id")
                    item_id = message_data.get("item_id")
                    if recipient_id and item_id:
                        await handle_request_trade_item(player_id, recipient_id, item_id)
                    else:
                        await player.send_message("error", {"message": "Missing recipient_id or item_id for trade_item."})
                elif message_type == "drop_item_to_world":
                    item_id = message_data.get("item_id")
                    if item_id:
                        await handle_request_drop_item_to_world(player_id, item_id)
                    else:
                        await player.send_message("error", {"message": "Missing item_id for drop_item_to_world."})
                else:
                    await player.send_message("error", {"message": f"Unknown message type: {message_type}"})
                    logging.warning(f"Unknown message type from {player_id}: {message_type}")
            except json.JSONDecodeError:
                await player.send_message("error", {"message": "Invalid JSON format."})
                logging.warning(f"Invalid JSON from {player_id}: {message}")
            except Exception as e:
                await player.send_message("error", {"message": f"Server error: {str(e)}"})
                logging.exception(f"Error processing message from {player_id}: {e}")

    except websockets.exceptions.ConnectionClosedOK:
        logging.info(f"Player {player_id} disconnected gracefully.")
    except websockets.exceptions.ConnectionClosed as e:
        logging.warning(f"Player {player_id} disconnected with error: {e}")
    finally:
        del PLAYERS[player_id]
        logging.info(f"Player {player_id} removed from active players.")

async def main():
    await initialize_world_items()
    async with websockets.serve(handler, "localhost", 8765):
        logging.info("Game server started on ws://localhost:8765")
        await asyncio.Future()  # Run forever

if __name__ == "__main__":
    asyncio.run(main())